import { isAlive } from "../../src/libs/process.js";

const SOULS_DIR = fromRoot(".claude", "souls");
const FREDDIE_KNOWLEDGE_DIR = fromRoot("vault", "studio", "memory", "freddie", "knowledge");
const FREDDIE_INBOX_DIR = fromRoot("vault", "studio", "memory", "freddie", "inbox");

function resolveAutoMemoryDir(): string {
  const home = process.env.HOME || process.env.USERPROFILE || "";
  const projectsDir = join(home, ".claude-personal", "projects");
  if (!existsSync(projectsDir)) return join(projectsDir, "unknown", "memory");

  // Claude Code encodes cwd as dash-separated path (e.g. d--PROJECTS-freddie-ai)
  // but drive letter casing varies — match case-insensitively
  const encoded = fromRoot().replace(/:/g, "-").replace(/[\\/]+/g, "-");
  const match = readdirSync(projectsDir).find(
    (d) => d.toLowerCase() === encoded.toLowerCase()
  );
  return join(projectsDir, match || encoded, "memory");
}

const AUTO_MEMORY_DIR = resolveAutoMemoryDir();

// ── Load all soul files ──────────────────────────────────────────────────

function loadSouls(): string[] {
  if (!existsSync(SOULS_DIR)) return [];
  const files = readdirSync(SOULS_DIR)
    .filter((f) => f.endsWith(".md"))
    .sort();

  const sections: string[] = [];
  for (const file of files) {
    const name = basename(file, ".md");
    const content = readFileSync(join(SOULS_DIR, file), "utf-8").trim();
    sections.push(`── ${name} ──\n${content}`);
  }
  return sections;
}

// ── Load Freddie's knowledge ─────────────────────────────────────────────

function loadFreddieKnowledge(): string[] {
  if (!existsSync(FREDDIE_KNOWLEDGE_DIR)) return [];
  const files = readdirSync(FREDDIE_KNOWLEDGE_DIR)
    .filter((f) => f.endsWith(".md"))
    .sort();

  const sections: string[] = [];
  for (const file of files) {
    const name = basename(file, ".md");
    const content = readFileSync(join(FREDDIE_KNOWLEDGE_DIR, file), "utf-8").trim();
    sections.push(`── ${name} ──\n${content}`);
  }
  return sections;
}

// ── Load Freddie's inbox ─────────────────────────────────────────────────

function loadFreddieInbox(): string[] {
  if (!existsSync(FREDDIE_INBOX_DIR)) return [];
  const files = readdirSync(FREDDIE_INBOX_DIR)
    .filter((f) => f.endsWith(".md"))
    .sort();

  const sections: string[] = [];
  for (const file of files) {
    const name = basename(file, ".md");
    const content = readFileSync(join(FREDDIE_INBOX_DIR, file), "utf-8").trim();
    sections.push(`── ${name} ──\n${content}`);
  }
  return sections;
}

// ── ASL daemon liveness probe ────────────────────────────────────────────

function loadDaemonStatus(): string[] {
  try {
    const pidFile = fromRoot("out", "asl-daemon.pid");
    let raw: string;
    try {
      raw = readFileSync(pidFile, "utf-8").trim();
    } catch {
      // PID file missing — daemon has never been started or was cleanly stopped
      return [
        "ASL daemon: STOPPED",
        "  Run `npm run asl:start` to enable background learning, or `bun run tool asl-sync` for a one-shot catch-up.",
      ];
    }
    const pid = parseInt(raw, 10);
    if (isNaN(pid)) {
      // Corrupted PID file — treat as stopped
      return [
        "ASL daemon: STOPPED",
        "  Run `npm run asl:start` to enable background learning, or `bun run tool asl-sync` for a one-shot catch-up.",
      ];
    }
    if (isAlive(pid)) {
      return [`ASL daemon: RUNNING (PID: ${pid})`];
    }
    return [
      `ASL daemon: STALE PID (was ${pid})`,
      "  Run `npm run asl:start` to restart.",
    ];
  } catch {
    // Catastrophic failure — swallow and return empty so session boot is never blocked
    return [];
  }
}

// ── Last session finder ───────────────────────────────────────────────────

function findLastSession(): string | null {
  if (!existsSync(AUTO_MEMORY_DIR)) return null;

  const sessionFiles = readdirSync(AUTO_MEMORY_DIR)
    .filter((f) => f.startsWith("project_session_") && f.endsWith(".md"))
    .sort()
    .reverse();

  if (sessionFiles.length === 0) return null;

  const latest = sessionFiles[0];
  const content = readFileSync(join(AUTO_MEMORY_DIR, latest), "utf-8");

  const dateMatch = latest.match(/project_session_(\d{4})(\d{2})(\d{2})/);
  const date = dateMatch ? `${dateMatch[1]}-${dateMatch[2]}-${dateMatch[3]}` : "unknown";

  const descMatch = content.match(/^description:\s*(.+)$/m);
  const summary =
    descMatch?.[1] ||
    content
      .split("\n")
      .find(
        (l) =>
          l.length > 10 &&
          !l.startsWith("---") &&
          !l.startsWith("name:") &&
          !l.startsWith("type:")
      )
      ?.trim() ||
    "No summary available";

  const trimmed = summary.length > 120 ? summary.slice(0, 117) + "..." : summary;
  return `Last session (${date}): ${trimmed}`;
}

// ── External MCP readiness probe ─────────────────────────────────────────

/**
 * Load external MCP readiness status. Returns formatted lines for the
 * session briefing, or an empty array when:
 *   - the feature flag is disabled (aslReadiness.externalMcp.enabled: false)
 *   - a catastrophic error occurs (session start must never be blocked)
 *
 * Uses dynamic import so the heavy module is only loaded when the flag is on.
 * When the flag is off, this function returns [] before any import runs —
 * cold-start cost is zero.
 */
async function loadMcpReadiness(): Promise<string[]> {
  try {
    // Fast-path: check the flag via a minimal read before paying the import cost.
    // Config lives in .claude/asl-readiness.json (not settings.json — Claude Code's
    // runtime validator rejects unknown top-level keys in settings.json).
    let enabled = false;
    try {
      const raw = readFileSync(fromRoot(".claude", "asl-readiness.json"), "utf-8");
      const parsed = JSON.parse(raw) as Record<string, unknown>;
      const extMcp = parsed["externalMcp"] as Record<string, unknown> | undefined;
      enabled = extMcp?.["enabled"] === true;
    } catch {
      // Missing or malformed config — feature is off
    }

    if (!enabled) return [];

    // Dynamic import — only paid when the flag is on
    const { checkExternalMcpReadiness } = await import("../../src/libs/mcp-readiness.js");
    const result = await checkExternalMcpReadiness();

    if (!result.enabled) return [];

    const total = result.ready.length + result.notReady.length;
    if (total === 0) {
      return ["External MCP: none installed"];
    }

    const lines: string[] = [];
    for (const entry of result.ready) {
      lines.push(`External MCP: ${entry.name} READY`);
    }
    for (const entry of result.notReady) {
      const errLabel = (entry.errorType ?? "UNKNOWN").toUpperCase();
      lines.push(`External MCP: ${entry.name} ${errLabel}`);
      if (entry.remediation) {
        lines.push(`  → ${entry.remediation}`);
      }
    }
    return lines;
  } catch {
    // Swallow all errors — never block session start
    return [];
  }
}

// ── Main ─────────────────────────────────────────────────────────────────

async function main() {
  const lines: string[] = [];

  const souls = loadSouls();
  if (souls.length > 0) {
    lines.push("═══ AGENT SOULS ═══");
    lines.push(souls.join("\n\n"));
    lines.push("");
  }

  const knowledge = loadFreddieKnowledge();
  if (knowledge.length > 0) {
    lines.push("═══ FREDDIE KNOWLEDGE ═══");
    lines.push(knowledge.join("\n\n"));
    lines.push("");
  }

  const inbox = loadFreddieInbox();
  if (inbox.length > 0) {
    lines.push("═══ FREDDIE INBOX ═══");
    lines.push(inbox.join("\n\n"));
    lines.push("");
  }

  const lastSession = findLastSession();
  if (lastSession) {
    lines.push("═══ SESSION CONTEXT ═══");
    lines.push(lastSession);
    lines.push("");
  }

  const daemonStatus = loadDaemonStatus();
  if (daemonStatus.length > 0) {
    lines.push("═══ ASL DAEMON ═══");
    lines.push(daemonStatus.join("\n"));
    lines.push("");
  }

  const mcpReadiness = await loadMcpReadiness();
  if (mcpReadiness.length > 0) {
    lines.push("═══ EXTERNAL MCP ═══");
    lines.push(mcpReadiness.join("\n"));
    lines.push("");
  }

  if (lines.length > 0) {
    process.stdout.write(lines.join("\n"));
  }
}

main()
  .catch(err => {
    // Never block session start
    process.stderr.write(`[startup] Error: ${err instanceof Error ? err.message : String(err)}\n`);
  })
  .finally(() => {
    process.exit(0);
  });

