// ─── Staged proposals sync ──────────────────────────────────

/**
 * Sync staged proposal files into brain.db.
 * Scans vault/studio/memory/{agent}/staged/ directories.
 * Hash-based incremental sync — only processes changed files.
 * Returns count of changed (upserted or removed) records.
 */
export async function syncStaged(opts?: { full?: boolean }): Promise<number> {
  const raw = getRawDb();
  let changed = 0;

  if (opts?.full) {
    raw.exec("DELETE FROM staged_proposals");
    raw.exec("DELETE FROM sync_meta WHERE table_name = 'staged_proposals'");
  }

  // Discover all staged files across all agents
  const stagedFiles: string[] = [];

  if (!existsSync(MEMORY_ROOT)) return 0;

  let agentDirs: import("fs").Dirent[];
  try {
    agentDirs = readdirSync(MEMORY_ROOT, { withFileTypes: true });
  } catch {
    return 0;
  }

  for (const agentEntry of agentDirs) {
    if (!agentEntry.isDirectory()) continue;
    const stagedDir = join(MEMORY_ROOT, agentEntry.name, "staged");
    if (!existsSync(stagedDir)) continue;

    const entries = readdirSync(stagedDir, { withFileTypes: true });
    for (const entry of entries) {
      if (entry.isFile() && entry.name.endsWith(".md")) {
        stagedFiles.push(join(stagedDir, entry.name));
      }
    }
  }

  const currentPaths = new Set<string>();

  for (const filePath of stagedFiles) {
    // Derive agent name from path: memory/{agent}/staged/{file}
    const parts = filePath.replace(/\\/g, "/").split("/");
    const stagedIdx = parts.lastIndexOf("staged");
    const agent = stagedIdx >= 1 ? parts[stagedIdx - 1] : "unknown";

    const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");
    currentPaths.add(sourcePath);

    const rawContent = readFileSync(filePath, "utf-8");
    const hash = hashFile(rawContent);

    // Check hash for incremental skip
    const existing = raw.prepare(
      "SELECT file_hash FROM staged_proposals WHERE source_path = ?"
    ).get(sourcePath) as { file_hash: string } | null;

    if (existing && existing.file_hash === hash && !opts?.full) continue;

    // Parse frontmatter using canonical staged parser (handles JSON-encoded values from fmEscape)
    const fm = parseStagedFrontmatter(rawContent);

    // Extract proposed change section body
    const changeMatch = rawContent.match(/## Proposed Change\r?\n\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
    const proposedChange = changeMatch ? changeMatch[1].trim() : "";

    // Extract reason from frontmatter (preferred) or ## Reason for Staging section
    const reasonFm = fm.reason ?? "";
    const reasonSectionMatch = rawContent.match(/## Reason for Staging\r?\n\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
    const reason = reasonFm || (reasonSectionMatch ? reasonSectionMatch[1].trim() : "");

    const title = fm.title ?? "";
    const section = fm.section ?? "";
    const changeType = fm.change_type ?? "modify";
    const status = fm.status ?? "pending";
    const createdAt = fm.created ?? now();
    const ts = now();

    raw.exec(`
      INSERT INTO staged_proposals (
        agent, title, section, change_type, proposed_change, reason,
        status, source_path, file_hash, created_at, updated_at
      )
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      ON CONFLICT(source_path) DO UPDATE SET
        agent=excluded.agent, title=excluded.title, section=excluded.section,
        change_type=excluded.change_type, proposed_change=excluded.proposed_change,
        reason=excluded.reason, status=excluded.status,
        file_hash=excluded.file_hash, updated_at=excluded.updated_at
    `.trim(), [agent, title, section, changeType, proposedChange, reason, status, sourcePath, hash, createdAt, ts] as any);

    // Upsert sync meta
    raw.exec(`
      INSERT INTO sync_meta (source_path, file_hash, table_name, synced_at)
      VALUES (?, ?, 'staged_proposals', ?)
      ON CONFLICT(source_path) DO UPDATE SET
        file_hash=excluded.file_hash, synced_at=excluded.synced_at
    `.trim(), [sourcePath, hash, ts] as any);

    changed++;
  }

  // Remove orphans — but check if the file moved to rejected/ first.
  // If it did, record the rejection in brain.db (backfill for files rejected
  // before ASL-0023 deployed, or rejected outside review-staged).
  const rows = raw.prepare("SELECT source_path FROM staged_proposals").all() as { source_path: string }[];
  for (const row of rows) {
    if (!currentPaths.has(row.source_path)) {
      // Check whether the file appears in the matching rejected/ dir
      const stagedPath = join(VAULT_STUDIO, row.source_path);
      const parts = row.source_path.replace(/\\/g, "/").split("/");
      const stagedIdx = parts.indexOf("staged");
      if (stagedIdx >= 1) {
        const agent = parts[stagedIdx - 1];
        const filename = parts[stagedIdx + 1];
        if (filename) {
          const rejectedPath = join(VAULT_STUDIO, "memory", agent, "rejected", filename);
          if (existsSync(rejectedPath)) {
            // File moved to rejected/ — record rejection as backfill (non-fatal)
            try {
              const rawContent = readFileSync(rejectedPath, "utf-8");
              const fm = parseStagedFrontmatter(rawContent);
              const changeMatch = rawContent.match(/## Proposed Change\r?\n\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
              const proposedChange = changeMatch ? changeMatch[1].trim() : "";
              const normalizedHash = createHash("sha256")
                .update(proposedChange.toLowerCase().replace(/[^\w\s]/g, "").replace(/\s+/g, " ").trim(), "utf8")
                .digest("hex").slice(0, 16);
              const rejectedSourcePath = relative(VAULT_STUDIO, rejectedPath).replace(/\\/g, "/");
              const { rejectedAt } = (() => {
                try {
                  return { rejectedAt: statSync(rejectedPath).mtime.toISOString() };
                } catch {
                  return { rejectedAt: new Date().toISOString() };
                }
              })();
              raw.exec(`
                INSERT INTO rejected_proposals (
                  agent, title, proposed_change, section, change_type, evidence,
                  rejection_reason, normalized_hash, source_path, rejected_at, created_at
                )
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(source_path) DO NOTHING
              `.trim(), [
                agent,
                fm.title ?? filename,
                proposedChange,
                fm.section ?? "",
                fm.change_type ?? "modify",
                "",
                null,
                normalizedHash,
                rejectedSourcePath,
                rejectedAt,
                new Date().toISOString(),
              ] as any);
            } catch {
              // Backfill failure is non-fatal
            }
          }
        }
      }
      raw.exec("DELETE FROM staged_proposals WHERE source_path = ?", [row.source_path] as any);
      raw.exec("DELETE FROM sync_meta WHERE source_path = ?", [row.source_path] as any);
      changed++;
    }
  }

  // Backfill rejected/ dirs — scan for files not yet in rejected_proposals
  scanRejectedDirs(raw);

  return changed;
}

/**
 * Scan all vault/studio/memory/{agent}/rejected/ directories and backfill
 * any files not yet recorded in rejected_proposals.
 * Called once per syncStaged run — idempotent via ON CONFLICT(source_path) DO NOTHING.
 */
function scanRejectedDirs(raw: import("bun:sqlite").Database): void {
  if (!existsSync(MEMORY_ROOT)) return;

  let agentDirs: import("fs").Dirent[];
  try {
    agentDirs = readdirSync(MEMORY_ROOT, { withFileTypes: true });
  } catch {
    return;
  }

