function scanRejectedDirs(raw: import("bun:sqlite").Database): void {
  if (!existsSync(MEMORY_ROOT)) return;

  let agentDirs: import("fs").Dirent[];
  try {
    agentDirs = readdirSync(MEMORY_ROOT, { withFileTypes: true });
  } catch {
    return;
  }

  for (const agentEntry of agentDirs) {
    if (!agentEntry.isDirectory()) continue;
    const agent = agentEntry.name;
    const rejectedDir = join(MEMORY_ROOT, agent, "rejected");
    if (!existsSync(rejectedDir)) continue;

    let files: string[];
    try {
      files = readdirSync(rejectedDir).filter(f => f.endsWith(".md"));
    } catch {
      continue;
    }

    for (const filename of files) {
      const filePath = join(rejectedDir, filename);
      const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");

      // Skip if already recorded
      const exists = raw.prepare(
        "SELECT id FROM rejected_proposals WHERE source_path = ?"
      ).get(sourcePath);
      if (exists) continue;

      try {
        const rawContent = readFileSync(filePath, "utf-8");
        const fm = parseStagedFrontmatter(rawContent);
        const changeMatch = rawContent.match(/## Proposed Change\r?\n\r?\n([\s\S]*?)(?=\r?\n## |\s*$)/);
        const proposedChange = changeMatch ? changeMatch[1].trim() : "";
        const normalizedHash = createHash("sha256")
          .update(proposedChange.toLowerCase().replace(/[^\w\s]/g, "").replace(/\s+/g, " ").trim(), "utf8")
          .digest("hex").slice(0, 16);
        let rejectedAt: string;
        try {
          rejectedAt = statSync(filePath).mtime.toISOString();
        } catch {
          rejectedAt = new Date().toISOString();
        }

        raw.exec(`
          INSERT INTO rejected_proposals (
            agent, title, proposed_change, section, change_type, evidence,
            rejection_reason, normalized_hash, source_path, rejected_at, created_at
          )
          VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
          ON CONFLICT(source_path) DO NOTHING
        `.trim(), [
          agent,
          fm.title ?? filename,
          proposedChange,
          fm.section ?? "",
          fm.change_type ?? "modify",
          "",
          null,
          normalizedHash,
          sourcePath,
          rejectedAt,
          new Date().toISOString(),
        ] as any);
      } catch {
        // Per-file failure is non-fatal
      }
    }
  }
}

// ─── Shared ──────────────────────────────────────────────────

/** Remove rows whose source files no longer exist on disk */
function removeOrphans(raw: import("bun:sqlite").Database, tableName: string, currentPaths: Set<string>): number {
  const table = tableName === "references" ? "'references'" : tableName;
  const rows = raw.prepare(`SELECT source_path FROM ${table}`).all() as { source_path: string }[];
  let removed = 0;

  for (const row of rows) {
    if (!currentPaths.has(row.source_path)) {
      raw.exec(`DELETE FROM ${table} WHERE source_path = ?`, [row.source_path] as any);
      raw.exec(`DELETE FROM sync_meta WHERE source_path = ?`, [row.source_path] as any);
      removed++;
    }
  }

  return removed;
}

/**
 * Quick check — counts how many files have changed since last sync
 * without actually syncing. Fast for boot checks.
 */
export async function checkSync(): Promise<SyncStatus> {
  const db = getDb();
  let memoriesChanged = 0;
  let memoriesTotal = 0;
  let refsChanged = 0;
  let refsTotal = 0;
  let removed = 0;

  // Check memory files
  const memFiles = findMdFiles(MEMORY_ROOT);
  const memPaths = new Set<string>();
  for (const filePath of memFiles) {
    const meta = parseMemoryPath(filePath);
    if (!meta) continue;
    memoriesTotal++;

    const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");
    memPaths.add(sourcePath);

    const rawContent = readFileSync(filePath, "utf-8");
    const hash = hashFile(rawContent);
    const existing = db.select().from(syncMeta).where(eq(syncMeta.sourcePath, sourcePath)).get();
    if (!existing || existing.fileHash !== hash) memoriesChanged++;
  }

  // Check reference files
  const refFiles = findMdFiles(REFS_ROOT);
  const refPaths = new Set<string>();
  for (const filePath of refFiles) {
    const meta = parseReferencePath(filePath);
    if (!meta) continue;
    refsTotal++;

    const sourcePath = relative(VAULT_STUDIO, filePath).replace(/\\/g, "/");
    refPaths.add(sourcePath);

    const rawContent = readFileSync(filePath, "utf-8");
    const hash = hashFile(rawContent);
    const existing = db.select().from(syncMeta).where(eq(syncMeta.sourcePath, sourcePath)).get();
    if (!existing || existing.fileHash !== hash) refsChanged++;
  }

  // Check project files (both locations)
  let projectsChanged = 0;
  let projectsTotal = 0;
  const raw = getRawDb();
  const projectFiles = findMdFiles(PROJECTS_ROOT);
  const docFiles = findMdFiles(DOCS_ROOT);
  const allProjectFiles = [...projectFiles, ...docFiles];
  for (const filePath of allProjectFiles) {
    projectsTotal++;
    const sourcePath = relative(fromRoot(), filePath).replace(/\\/g, "/");
    const rawContent = readFileSync(filePath, "utf-8");
    const hash = hashFile(rawContent);
    const existing = raw.prepare(
      "SELECT file_hash FROM project_chunks WHERE source_path = ? LIMIT 1"
    ).get(sourcePath) as { file_hash: string } | null;
    if (!existing || existing.file_hash !== hash) projectsChanged++;
  }

  // Count orphans in sync_meta
  const allSyncRows = raw_allSyncPaths(db);
  for (const row of allSyncRows) {
    if (row.tableName === "memories" && !memPaths.has(row.sourcePath)) removed++;
    if (row.tableName === "references" && !refPaths.has(row.sourcePath)) removed++;
  }

  return { memoriesChanged, memoriesTotal, refsChanged, refsTotal, projectsChanged, projectsTotal, removed };
}

function raw_allSyncPaths(db: ReturnType<typeof getDb>) {
  return db.select({ sourcePath: syncMeta.sourcePath, tableName: syncMeta.tableName }).from(syncMeta).all();
}

