87	function shortTitle(text: string, max = 60): string {
88	  // Cut at first — (em dash) or . after the initial phrase, if within limit
89	  const emDash = text.indexOf(' — ');
90	  if (emDash > 0 && emDash <= max) return text.slice(0, emDash);
91	  const dot = text.indexOf('. ');
92	  if (dot > 0 && dot <= max) return text.slice(0, dot);
93	  if (text.length <= max) return text;
