109	function loadTasks(date: string): TaskDisplay {
110	  const result: TaskDisplay = { lines: [], openCount: 0, inProgressCount: 0, doneCount: 0 };
111	  const path = `daily/${date}.md`;
112	  if (!noteExists(path)) return result;
113	
114	  const content = readNote(path);
