134	    const age = task.history.length > 0 ? ` (${task.history.length}d)` : '';
135	    const docs = task.links.length > 0 ? ` (docs: ${task.links.length})` : '';
136	    result.lines.push(`${marker} [${task.id}] ${shortTitle(task.content)}${docs}${age}`);
137	
