153	// ── Soul Updates ──────────────────────────────────────────────────────────
154	
155	interface SoulUpdateDisplay {
156	  applied: string[];   // formatted lines for auto-applied changes
157	  pending: string[];   // formatted lines for staged proposals needing review
158	  hasUpdates: boolean;
159	}
160	
161	function loadSoulUpdates(): SoulUpdateDisplay {
162	  const result: SoulUpdateDisplay = { applied: [], pending: [], hasUpdates: false };
163	
164	  // yesterday as ISO date string (YYYY-MM-DD)
165	  const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
166	
167	  // Auto-applied soul changes in the last 24h.
168	  // Grouped by agent and capped at PER_AGENT_CAP entries per agent to prevent
169	  // productive distill runs from drowning out the rest of the briefing.
170	  try {
171	    initBrain();
172	    const changes = getRecentSoulChanges(undefined, {
173	      since: yesterday,
174	      status: "auto-applied",
175	      limit: 50,
176	    });
177	
178	    // Preserve DESC order (most-recently-active agent first)
179	    const byAgent = new Map<string, typeof changes>();
180	    for (const c of changes) {
181	      const group = byAgent.get(c.agent);
182	      if (group) group.push(c);
183	      else byAgent.set(c.agent, [c]);
184	    }
185	
186	    const PER_AGENT_CAP = 2;
187	    for (const [agent, group] of byAgent) {
188	      const shown = group.slice(0, PER_AGENT_CAP);
189	      for (const c of shown) {
190	        const summary = c.changeSummary.length > 60
191	          ? c.changeSummary.slice(0, 60) + "…"
192	          : c.changeSummary;
193	        result.applied.push(`+ ${capitalize(agent)}: ${summary}`);
194	      }
195	      const extra = group.length - shown.length;
196	      if (extra > 0) {
197	        result.applied.push(`+ ${capitalize(agent)}: … and ${extra} more`);
198	      }
199	    }
200	  } catch {
201	    // silently omit on error
202	  }
203	
204	  // Pending staged proposals — all, regardless of age
205	  try {
206	    const proposals = getPendingProposals();
207	    for (const f of proposals) {
208	      const p = f.proposal;
209	      const label = p.title || (p.proposedChange.split(/\r?\n/)[0] ?? "");
210	      const preview = label.length > 40 ? label.slice(0, 40) + "…" : label;
211	      const reason = p.reason.length > 60 ? p.reason.slice(0, 60) + "…" : p.reason;
212	      result.pending.push(`? ${capitalize(p.agent)}: "${preview}" — ${reason}`);
213	    }
214	  } catch {
215	    // silently omit on error
216	  }
217	
218	  result.hasUpdates = result.applied.length > 0 || result.pending.length > 0;
219	  return result;
220	}
221	
222	// ── Suggestions ───────────────────────────────────────────────────────────
223	
224	function buildSuggestions(
225	  inboxStatuses: AgentMemoryStatus[],
226	  taskDisplay: TaskDisplay,
227	  soulUpdates: SoulUpdateDisplay
228	): string[] {
229	  const suggestions: string[] = [];
230	
231	  const needsConsolidation = inboxStatuses.filter((a) => a.inboxCount >= 3);
232	  for (const a of needsConsolidation) {
233	    suggestions.push(
234	      `${capitalize(a.agent)} has ${a.inboxCount} inbox items — consolidation ready`
235	    );
236	  }
237	
238	  const hasInbox = inboxStatuses.filter((a) => a.inboxCount > 0 && a.inboxCount < 3);
239	  if (hasInbox.length > 0) {
240	    const names = hasInbox
241	      .map((a) => `${capitalize(a.agent)} (${a.inboxCount})`)
242	      .join(", ");
243	    suggestions.push(`Inbox items: ${names}`);
244	  }
245	
246	  if (taskDisplay.openCount > 5) {
247	    suggestions.push(
248	      `${taskDisplay.openCount} open tasks — consider triaging or deferring some`
249	    );
250	  }
251	
252	  if (soulUpdates.pending.length > 0) {
253	    suggestions.push(
254	      `${soulUpdates.pending.length} soul change(s) staged for review`
255	    );
256	  }
257	
258	  return suggestions;
259	}
260	
261	function capitalize(s: string): string {
262	  return s.charAt(0).toUpperCase() + s.slice(1);
263	}
264	
265	// ── Main ──────────────────────────────────────────────────────────────────
266	
267	function main() {
268	  const { date, time } = now();
269	  const hour = parseInt(time.slice(0, 2), 10);
270	  const greeting = getGreeting(hour);
271	  const inboxStatuses = scanInbox();
272	  const taskDisplay = loadTasks(date);
273	  const soulUpdates = loadSoulUpdates();
274	  const suggestions = buildSuggestions(inboxStatuses, taskDisplay, soulUpdates);
275	
276	  const lines: string[] = [];
277	
278	  lines.push(greeting);
279	  lines.push("");
280	
281	  lines.push("━━ Briefing ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
282	  lines.push("");
283	
284	  if (taskDisplay.lines.length > 0) {
285	    lines.push("Tasks:");
286	    for (const line of taskDisplay.lines) {
287	      lines.push(`  ${line}`);
288	    }
289	    lines.push("");
290	    lines.push(
291	      `  Summary: ${taskDisplay.openCount} Open | ${taskDisplay.inProgressCount} In-Progress | ${taskDisplay.doneCount} Done`
292	    );
293	    lines.push("");
294	  } else {
295	    lines.push("Tasks: No open or in-progress tasks.");
296	    lines.push("");
297	  }
298	
299	  if (soulUpdates.hasUpdates) {
300	    lines.push("Soul Updates:");
301	    if (soulUpdates.applied.length > 0) {
302	      lines.push("  Applied:");
303	      for (const line of soulUpdates.applied) {
304	        lines.push(`    ${line}`);
305	      }
306	    }
307	    if (soulUpdates.pending.length > 0) {
308	      lines.push("  Review needed:");
309	      for (const line of soulUpdates.pending) {
310	        lines.push(`    ${line}`);
311	      }
312	    }
313	    lines.push("");
314	  }
315	
316	  if (suggestions.length > 0) {
317	    lines.push("Suggested:");
318	    for (const s of suggestions) {
319	      lines.push(`  > ${s}`);
320	    }
321	    lines.push("");
322	  }
323	
324	  lines.push("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
325	
326	  process.stdout.write(lines.join("\n"));
327	}
328	
329	try {
330	  main();
331	} catch (err) {
332	  process.stderr.write(
333	    `[morning] Error: ${err instanceof Error ? err.message : String(err)}\n`
334	  );
335	}
336	
337	process.exit(0);
