    result.lines.push(`${marker} [${task.id}] ${shortTitle(task.content)}${docs}${age}`);

    if (task.status === 'in_progress') result.inProgressCount++;
    else result.openCount++;

    for (const sub of task.subtasks) {
      const subIsOpen = sub.status === 'todo' || sub.status === 'in_progress';
      if (!subIsOpen) continue;
      const subMarker = sub.status === 'in_progress' ? '[/]' : '[ ]';
      const subAge = sub.history.length > 0 ? ` (${sub.history.length}d)` : '';
      result.lines.push(`    ${subMarker} [${sub.id}] ${shortTitle(sub.content, 50)}${subAge}`);
    }
  }

  return result;
}

// ── Soul Updates ──────────────────────────────────────────────────────────

interface SoulUpdateDisplay {
  applied: string[];   // formatted lines for auto-applied changes
  pending: string[];   // formatted lines for staged proposals needing review
  hasUpdates: boolean;
}

function loadSoulUpdates(): SoulUpdateDisplay {
  const result: SoulUpdateDisplay = { applied: [], pending: [], hasUpdates: false };

  // yesterday as ISO date string (YYYY-MM-DD)
  const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString().slice(0, 10);

  // Auto-applied soul changes in the last 24h.
  // Grouped by agent and capped at PER_AGENT_CAP entries per agent to prevent
  // productive distill runs from drowning out the rest of the briefing.
  try {
    initBrain();
    const changes = getRecentSoulChanges(undefined, {
      since: yesterday,
      status: "auto-applied",
      limit: 50,
    });

    // Preserve DESC order (most-recently-active agent first)
    const byAgent = new Map<string, typeof changes>();
    for (const c of changes) {
      const group = byAgent.get(c.agent);
      if (group) group.push(c);
      else byAgent.set(c.agent, [c]);
    }

    const PER_AGENT_CAP = 2;
    for (const [agent, group] of byAgent) {
      const shown = group.slice(0, PER_AGENT_CAP);
      for (const c of shown) {
        const summary = c.changeSummary.length > 60
          ? c.changeSummary.slice(0, 60) + "…"
          : c.changeSummary;
        result.applied.push(`+ ${capitalize(agent)}: ${summary}`);
      }
      const extra = group.length - shown.length;
      if (extra > 0) {
        result.applied.push(`+ ${capitalize(agent)}: … and ${extra} more`);
      }
    }
  } catch {
    // silently omit on error
  }

  // Pending staged proposals — all, regardless of age
  try {
    const proposals = getPendingProposals();
    for (const f of proposals) {
      const p = f.proposal;
      const label = p.title || (p.proposedChange.split(/\r?\n/)[0] ?? "");
      const preview = label.length > 40 ? label.slice(0, 40) + "…" : label;
      const reason = p.reason.length > 60 ? p.reason.slice(0, 60) + "…" : p.reason;
      result.pending.push(`? ${capitalize(p.agent)}: "${preview}" — ${reason}`);
    }
  } catch {
    // silently omit on error
  }

  result.hasUpdates = result.applied.length > 0 || result.pending.length > 0;
  return result;
}

// ── Suggestions ───────────────────────────────────────────────────────────

function buildSuggestions(
  inboxStatuses: AgentMemoryStatus[],
  taskDisplay: TaskDisplay,
  soulUpdates: SoulUpdateDisplay
): string[] {
  const suggestions: string[] = [];

  const needsConsolidation = inboxStatuses.filter((a) => a.inboxCount >= 3);
  for (const a of needsConsolidation) {
    suggestions.push(
      `${capitalize(a.agent)} has ${a.inboxCount} inbox items — consolidation ready`
    );
  }

  const hasInbox = inboxStatuses.filter((a) => a.inboxCount > 0 && a.inboxCount < 3);
  if (hasInbox.length > 0) {
    const names = hasInbox
      .map((a) => `${capitalize(a.agent)} (${a.inboxCount})`)
      .join(", ");
    suggestions.push(`Inbox items: ${names}`);
  }

  if (taskDisplay.openCount > 5) {
    suggestions.push(
      `${taskDisplay.openCount} open tasks — consider triaging or deferring some`
    );
  }

  if (soulUpdates.pending.length > 0) {
    suggestions.push(
      `${soulUpdates.pending.length} soul change(s) staged for review`
    );
  }

  return suggestions;
}

function capitalize(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

// ── Main ──────────────────────────────────────────────────────────────────

function main() {
  const { date, time } = now();
  const hour = parseInt(time.slice(0, 2), 10);
  const greeting = getGreeting(hour);
  const inboxStatuses = scanInbox();
  const taskDisplay = loadTasks(date);
  const soulUpdates = loadSoulUpdates();
  const suggestions = buildSuggestions(inboxStatuses, taskDisplay, soulUpdates);

  const lines: string[] = [];

  lines.push(greeting);
  lines.push("");

  lines.push("━━ Briefing ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
  lines.push("");

  if (taskDisplay.lines.length > 0) {
    lines.push("Tasks:");
    for (const line of taskDisplay.lines) {
      lines.push(`  ${line}`);
    }
    lines.push("");
    lines.push(
      `  Summary: ${taskDisplay.openCount} Open | ${taskDisplay.inProgressCount} In-Progress | ${taskDisplay.doneCount} Done`
    );
    lines.push("");
  } else {
    lines.push("Tasks: No open or in-progress tasks.");
    lines.push("");
  }

  if (soulUpdates.hasUpdates) {
    lines.push("Soul Updates:");
    if (soulUpdates.applied.length > 0) {
      lines.push("  Applied:");
      for (const line of soulUpdates.applied) {
        lines.push(`    ${line}`);
      }
    }
    if (soulUpdates.pending.length > 0) {
      lines.push("  Review needed:");
      for (const line of soulUpdates.pending) {
        lines.push(`    ${line}`);
      }
    }
    lines.push("");
  }

  if (suggestions.length > 0) {
    lines.push("Suggested:");
    for (const s of suggestions) {
      lines.push(`  > ${s}`);
    }
    lines.push("");
  }

  lines.push("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

  process.stdout.write(lines.join("\n"));
}

try {
  main();
} catch (err) {
  process.stderr.write(
    `[morning] Error: ${err instanceof Error ? err.message : String(err)}\n`
  );
}

process.exit(0);

