const d = process.env.SUNO_DEVICE_ID || "";

function analyze(name, v) {
  console.log(`\n─── ${name} (length=${v.length}) ───`);
  console.log("first char code:", v.charCodeAt(0));
  console.log("last char code:", v.charCodeAt(v.length-1));

  // Show positions of any suspicious chars (quotes, whitespace, non-ASCII)
  const suspicious = [];
  for (let i = 0; i < v.length; i++) {
    const c = v[i];
    const code = v.charCodeAt(i);
    if (c === "\"" || c === "'"'"'" || c === "\\" || code < 32 || code > 126) {
      suspicious.push({ pos: i, char: c === "\"" ? "DQ" : c === "'"'"'" ? "SQ" : c === "\\" ? "BS" : `code${code}` });
    }
  }
  console.log("suspicious char positions:", JSON.stringify(suspicious));

  // Show the position-masked token: . for normal chars, the symbol for suspicious
  let mask = "";
  for (let i = 0; i < v.length; i++) {
    const c = v[i];
    if (c === "\"") mask += "\"";
    else if (c === "'"'"'") mask += "'"'"'";
    else if (c === "\\") mask += "\\";
    else if (c.charCodeAt(0) < 32) mask += "?";
    else if (c === " ") mask += "_";
    else mask += ".";
  }
  console.log("position mask:", mask);
}

analyze("SUNO_BROWSER_TOKEN", t);
analyze("SUNO_DEVICE_ID", d);
