// Default browser user-agent matching what Chrome sends to suno.com.
// Intentionally realistic — Suno's backend may reject requests with
// a non-browser UA or missing UA. Update periodically if Suno's middleware
// gets stricter about UA matching.
const DEFAULT_USER_AGENT =
  "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/141.0.0.0 Safari/537.36";

export function sunoHeaders(extra?: Record<string, string>): Record<string, string> {
  const authorization = process.env.SUNO_AUTHORIZATION ?? "";
  const token = process.env.SUNO_BROWSER_TOKEN ?? "";
  const deviceId = process.env.SUNO_DEVICE_ID ?? "";

  // Normalize Authorization header: if user stored just the JWT without
  // "Bearer " prefix, prepend it. If they stored the full "Bearer xyz"
  // string, pass through as-is.
  const authHeader = authorization.startsWith("Bearer ")
    ? authorization
    : authorization
      ? `Bearer ${authorization}`
      : "";

  return {
    ...(authHeader ? { authorization: authHeader } : {}),
    "browser-token": token,
    "device-id": deviceId,
    origin: "https://suno.com",
    referer: "https://suno.com/",
    accept: "application/json",
    "accept-language": "en-US,en;q=0.9",
    "user-agent": DEFAULT_USER_AGENT,
    ...extra,
  };
}

