bun -e '
import { readFileSync } from "fs";
const har = JSON.parse(readFileSync("C:/Users/odiem/Downloads/suno.com.har", "utf-8"));
const entries = har.log.entries;

// Filter to just Suno + S3 relevant endpoints
const relevant = entries.filter((e: any) => {
  const url = e.request.url;
  return (
    url.includes("studio-api-prod.suno.com/api/uploads/audio/") ||
    url.includes("studio-api-prod.suno.com/api/gen/") ||
    url.includes("suno-uploads.s3.amazonaws.com")
  );
}).sort((a: any, b: any) => new Date(a.startedDateTime).getTime() - new Date(b.startedDateTime).getTime());

console.log(`Found ${relevant.length} relevant requests\n`);

let prevEnd = 0;
for (const e of relevant) {
  const startMs = new Date(e.startedDateTime).getTime();
  const durationMs = Math.round(e.time);
  const endMs = startMs + durationMs;
  const gapFromPrevEnd = prevEnd === 0 ? 0 : startMs - prevEnd;

  // Extract path + short method label
  let path = e.request.url
    .replace("https://studio-api-prod.suno.com", "SUNO")
    .replace("https://suno-uploads.s3.amazonaws.com", "S3");
  // Redact UUIDs
  path = path.replace(/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/g, "{id}");
  if (path.length > 65) path = path.slice(0, 62) + "...";

  const method = e.request.method.padEnd(7);
  const status = String(e.response.status).padStart(3);
  const gap = String(gapFromPrevEnd + "ms").padStart(8);
  const dur = String(durationMs + "ms").padStart(6);

  // OPTIONS preflights are noise - mark them
  const marker = method.trim() === "OPTIONS" ? "·" : "→";

  console.log(`${marker} ${method} ${status}  gap:${gap}  dur:${dur}  ${path}`);
  prevEnd = endMs;
}
