// Polling config — intentionally slower than the HAR-observed browser
// interval (~4000ms) to stay well under any rate-limit threshold.
export const POLL_INTERVAL_MS = 5000;
export const POLL_TIMEOUT_MS = 180_000; // 3 min — matches slower poll interval

// S3 retry config (step 2 only — no other retries per spec A5)
export const S3_MAX_RETRIES = 3;
export const S3_BACKOFF_MS = [1000, 2000, 4000] as const;

// Inter-step pacing — intentionally ≥1.5× the HAR-observed browser intervals.
// Derived from analysis of a real user session on 2026-04-09 (see ADR in
// suno-extract-meta task doc). Goal: never look faster than a real browser.
// All values are "wait BEFORE calling the named step".
export const PACING = {
  afterStep1_beforeS3: 1_500,        // HAR: 430ms
  afterStep2_beforeUploadFinish: 3_000, // HAR: 1874ms — let S3 commit
  afterStep3_beforeFirstPoll: 1_500, // HAR: 503ms
  afterStep4_beforeInitClip: 5_000,  // HAR: 29ms — CRITICAL: give Suno time to generate clip image, prevents image_moderation_error on step 6
  afterStep5_beforeSetMetadata: 1_500, // HAR: 436ms
  afterStep6_beforeSetAudioDesc: 1_500, // HAR: 558ms
} as const;

// Image moderation retry — if step 6 returns image_moderation_error
// (transient race where the clip image hasn't finished generating),
// wait and retry once. This is a known race condition.
export const IMAGE_MODERATION_RETRY_WAIT_MS = 5_000;

// Terminal statuses that stop polling (any non-"complete" final state)
const TERMINAL_STATUSES = new Set(["failed", "moderation_rejected", "error", "rejected"]);

// Sleep helper
export async function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

