export async function extractMeta(filePath: string): Promise<SunoExtractResult> {
  const validationError = validateInputs(filePath);
  if (validationError) {
    throw new SunoError(validationError.message, validationError.code);
  }

  const filename = basename(filePath);
  const fileBlob = Bun.file(filePath);
  const sizeBytes = fileBlob.size;

  // Step 1 — create upload session
  const { id: uploadId, url: s3Url, fields } = await step1CreateUploadSession();
  await sleep(PACING.afterStep1_beforeS3);

  // Step 2 — S3 upload (3x retry, step 2 only)
  await step2S3Upload(s3Url, fields, filePath);
  await sleep(PACING.afterStep2_beforeUploadFinish);

  // Step 3 — notify Suno upload is complete
  await step3UploadFinish(uploadId, filename);
  await sleep(PACING.afterStep3_beforeFirstPoll);

  // Step 4 — poll for Suno analysis (Gemini on their backend runs here)
  await step4PollForComplete(uploadId);

  // CRITICAL PACING: wait before initialize-clip to let Suno's backend
  // finish generating the clip image. Without this delay, step 6
  // (set_metadata) hits image_moderation_error because the image
  // doesn't exist yet. Observed 2026-04-09 during manual testing.
  await sleep(PACING.afterStep4_beforeInitClip);

  // Step 5 — initialize clip; returns clip_id (DISTINCT from uploadId — never shadow)
  const { clipId, title, imageUrl: clipImageUrl } = await step5InitializeClip(uploadId);
  await sleep(PACING.afterStep5_beforeSetMetadata);

  // Step 6 — acknowledge and receive lyrics. Suno's image moderation can
  // race with clip image generation; if we see image_moderation_error,
  // wait and retry once per the spec (transient condition).
  let lyrics: string;
  try {
    lyrics = await step6FetchLyrics(clipId, title, clipImageUrl);
  } catch (err) {
    if (err instanceof SunoError && err.message.includes("image_moderation_error")) {
      await sleep(IMAGE_MODERATION_RETRY_WAIT_MS);
      lyrics = await step6FetchLyrics(clipId, title, clipImageUrl);
    } else {
      throw err;
    }
  }
  await sleep(PACING.afterStep6_beforeSetAudioDesc);

  // Step 7 — acknowledge and receive style prose (already computed in step 4)
  const { audioUrl, imageUrl, styleProse, displayTags, durationSeconds, hasVocal } =
    await step7FetchStyle(clipId);

  return {
    file: { path: filePath, filename, size_bytes: sizeBytes },
    upload_id: uploadId,
    clip_id: clipId,
    audio_url: audioUrl,
    image_url: imageUrl,
    lyrics,
    style_prose: styleProse,
    display_tags: displayTags,
    duration_seconds: durationSeconds,
    has_vocal: hasVocal,
    extracted_at: new Date().toISOString(),
  };
}

